var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"엣취…!","JPN":" くしゅん……！","ENG":" Ah-choo!","TWN":"哈啾…！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"죄송합니다. 오늘 합동훈련을 소총수 분들과 함께 진행했는데… 헤엣취!","JPN":" 申し訳ありません。本日は小銃手の方々と共に合同訓練を行いましたが……へくしゅん！","ENG":" My apologies. Today's joint training was with the riflemen and– AH-CHOO!","TWN":"抱歉，今天和步槍手一起集訓…哈啾！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"급한 나머지 알러지 약을 먹는 걸 깜박했네요.","JPN":" 急いでいたのでアレルギーの薬を飲み忘れていました。","ENG":" I was in a rush and forgot to take my allergy meds.","TWN":"太匆忙結果就忘記吃過敏藥。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저도 압니다. 화약과 상성이 맞지 않는 군인이라니 우습죠.","JPN":" 私もわかっています。火薬との相性が悪い軍人なんておかしいでしょう。","ENG":" I know. A soldier who's allergic to gunpowder. Funny, right?","TWN":"我也知道很好笑，身為一個軍人卻對火藥過敏。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"단점을 개의치 않는 모습이 멋있다니… 그런 낯부끄러운 말씀을 하면서 눈 하나 깜짝 않으시네요.","JPN":"短所を気にしない姿がカッコいいだなて……そんな恥ずかしいことを言いながら眉毛ひとつも動かさないんですね。","ENG":"You think it's admirable that I don't mind my flaws...? You can say this embarrassing thing without even batting an eye.","TWN":"我不在意缺點的態度很帥氣嗎…你竟然可以臉不紅氣不喘地說出這麼令人害羞的話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…제가 의사 대신 군인이 되길 결정한 이유 말입니까?","JPN":" ……私が医者ではなく、軍人になると決めた理由ですか？","ENG":" ...The reason why I chose to be a soldier and not a doctor?","TWN":"…你知道我決定不當醫生，而是選擇當軍人的原因嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"병원에서 싸우다 다친 사람들을 기다리는 것보단, 현장에서 그들과 함께 싸우는 편이 더 많은 인명을 구할 수 있다고 믿기 때문입니다.","JPN":" 病院で戦って怪我をした人を待っているよりは、現場で彼らと一緒に戦った方がもっと多くの人を助けられると信じているからです。","ENG":" That's because I believe I can save more people fighting on the frontlines and waiting in hospitals to treat the injured.","TWN":"因為我相信與其在醫院裡等受傷的人上門，不如直接上戰場和他們一起並肩作戰，這樣反而可以拯救更多性命。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"의사가 이런 힘을 갖게 된다면 누구라도 저와 같은 생각을 하겠죠.","JPN":" 医者がこんな力を手に入れたら、誰でも私と同じ考えをするはずです。","ENG":" Any doctor with powers like mine would think the same thing.","TWN":"我相信醫生只要有這樣的能力，都會和我有一樣的想法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고, 당신이 가진 입지는 제가 가진 이 워치보다 훨씬 많은 사람을 구할 수 있을 겁니다.","JPN":" そして、あなたの立場は私が持っているこのウォッチよりもっと多くの人を助けられるはずです。","ENG":" Also, you can save more people in the position you're in than I can with this Watch.","TWN":"而且以你的地位，能夠拯救的人應該比我的能量環還多。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"비록 신체적으로는 연약하지만 자신의 책무 앞에선 누구보다 강한 사람.","JPN":" 身体的には弱いですが、自分の責務の前では誰よりも強い人。","ENG":" A person who may be physically weak, but is stronger than anyone when it comes to pulling one's own weight.","TWN":"雖然身體虛弱，但面對職責卻比誰都要堅強。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신도 틀림없이 그런 부류의 사람이라고 생각합니다.","JPN":" あなたも間違いなくそういう類の人だと思います。","ENG":" I'm certain that's you.","TWN":"我相信你也是屬於這一類的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};